/*---------------------------------------------------------------------------------------------
 *  HIM Inspector Service - Event Bus and Types
 *  Centralized event definitions for AI monitoring
 *--------------------------------------------------------------------------------------------*/

import { Event } from 'vscode';

/*---------------------------------------------------------------------------------------------
 * Event Types
 *--------------------------------------------------------------------------------------------*/

export type AgentThinkingStartEvent = {
    type: 'agent_thinking_start';
    data: {
        timestamp: number;
        message?: string;
    };
};

export type AgentCodeStartEvent = {
    type: 'agent_code_start';
    data: {
        timestamp: number;
        language: string;
    };
};

export type AgentCodeChunkEvent = {
    type: 'agent_code_chunk';
    data: {
        line: string;
        lineNumber: number;
        totalLines: number;
        isComplete: boolean;
    };
};

export type AgentCodeCompleteEvent = {
    type: 'agent_code_complete';
    data: {
        timestamp: number;
        totalLines: number;
        code: string;
    };
};

export type ExecStartEvent = {
    type: 'exec_start';
    data: {
        lineNumber: number;
        lineContent: string;
        timestamp: number;
    };
};

export type ExecLineEvent = {
    type: 'exec_line';
    data: {
        lineNumber: number;
        status: 'running' | 'success' | 'error';
        output?: string;
        error?: string;
    };
};

export type ExecCompleteEvent = {
    type: 'exec_complete';
    data: {
        timestamp: number;
        duration: number;
        linesExecuted: number;
    };
};

export type ExecErrorEvent = {
    type: 'exec_error';
    data: {
        lineNumber: number;
        error: string;
        errorType: string;
    };
};

export type StreamEvent = {
    type: 'stream_event';
    data: {
        action: 'init' | 'say' | 'file_read' | 'file_written' | 'execute_start' | 'execute_done' | 'dir_list' | 'cwd_changed' | 'error' | 'exception';
        data: unknown;
        timestamp: number;
    };
};

export type ClearEvent = {
    type: 'clear';
    data: null;
};

export type HimInspectorEvent =
    | AgentThinkingStartEvent
    | AgentCodeStartEvent
    | AgentCodeChunkEvent
    | AgentCodeCompleteEvent
    | ExecStartEvent
    | ExecLineEvent
    | ExecCompleteEvent
    | ExecErrorEvent
    | StreamEvent
    | ClearEvent;

/*---------------------------------------------------------------------------------------------
 * HIM Inspector Service Interface
 *--------------------------------------------------------------------------------------------*/

export interface IHimInspectorService {
    readonly onAgentTrace: Event<HimInspectorEvent>;

    startThinking(message?: string): void;
    startCodeGeneration(language?: string): void;
    addCodeChunk(line: string, lineNumber: number, totalLines: number, isComplete: boolean): void;
    completeCodeGeneration(totalLines: number, code: string): void;

    startExecution(lineNumber: number, lineContent: string): void;
    updateExecution(lineNumber: number, status: 'running' | 'success' | 'error', output?: string, error?: string): void;
    completeExecution(duration: number, linesExecuted: number): void;
    reportExecutionError(lineNumber: number, error: string, errorType: string): void;

    emitStreamEvent(action: StreamEvent['data']['action'], data: unknown): void;
    clear(): void;
}

/*---------------------------------------------------------------------------------------------
 * Mock Implementation for Testing
 *--------------------------------------------------------------------------------------------*/

export class MockHimInspectorService implements IHimInspectorService {
    private _onAgentTrace = new Set<(event: HimInspectorEvent) => void>();

    get onAgentTrace(): Event<HimInspectorEvent> {
        return (listener) => {
            this._onAgentTrace.add(listener);
            return () => this._onAgentTrace.delete(listener);
        };
    }

    private emit(event: HimInspectorEvent): void {
        for (const listener of this._onAgentTrace) {
            try {
                listener(event);
            } catch (e) {
                console.error('[HimInspector] Listener error:', e);
            }
        }
    }

    startThinking(message?: string): void {
        this.emit({
            type: 'agent_thinking_start',
            data: { timestamp: Date.now(), message }
        });
    }

    startCodeGeneration(language = 'python'): void {
        this.emit({
            type: 'agent_code_start',
            data: { timestamp: Date.now(), language }
        });
    }

    addCodeChunk(line: string, lineNumber: number, totalLines: number, isComplete: boolean): void {
        this.emit({
            type: 'agent_code_chunk',
            data: { line, lineNumber, totalLines, isComplete }
        });
    }

    completeCodeGeneration(totalLines: number, code: string): void {
        this.emit({
            type: 'agent_code_complete',
            data: { timestamp: Date.now(), totalLines, code }
        });
    }

    startExecution(lineNumber: number, lineContent: string): void {
        this.emit({
            type: 'exec_start',
            data: { lineNumber, lineContent, timestamp: Date.now() }
        });
    }

    updateExecution(lineNumber: number, status: 'running' | 'success' | 'error', output?: string, error?: string): void {
        this.emit({
            type: 'exec_line',
            data: { lineNumber, status, output, error }
        });
    }

    completeExecution(duration: number, linesExecuted: number): void {
        this.emit({
            type: 'exec_complete',
            data: { timestamp: Date.now(), duration, linesExecuted }
        });
    }

    reportExecutionError(lineNumber: number, error: string, errorType: string): void {
        this.emit({
            type: 'exec_error',
            data: { lineNumber, error, errorType }
        });
    }

    emitStreamEvent(action: StreamEvent['data']['action'], data: unknown): void {
        this.emit({
            type: 'stream_event',
            data: { action, data, timestamp: Date.now() }
        });
    }

    clear(): void {
        this.emit({ type: 'clear', data: null });
    }
}

/*---------------------------------------------------------------------------------------------
 * Webview Message Types
 *--------------------------------------------------------------------------------------------*/

export interface HimInspectorMessage {
    type: string;
    data: unknown;
}

